'use strict';
const $ = s => document.querySelector(s);
const $$ = s => Array.from(document.querySelectorAll(s));
let MANIFEST=null, META=[], BY_ID=new Map(), BUCKET=new Map(), DATA_CACHE=new Map();
let renderStop=false, currentOpen=null, selectedOrigin=null, viewState={rot:0,fx:false,fy:false};
let DRAW_SELECTED=new Set(), DRAW_GRID_N=19, DRAW_AUTO_ORIGIN=null, NEIGHBOR_TASKS=[], EDGE_DICT=[], MULT_DICT=[];
let BLOWUP_LAST=null;
const MIDX={id:0,cno:1,off:2,Vol:3,V:4,B:5,I:6,N:7,lw:8,box:9,content:10,smooth:11,src:12,edge:13,prim:14,maxE:15,minE:16,cent:17,mult:18,srcCount:19};
function id(n){return 'LP'+String(n).padStart(6,'0')}
function gcd(a,b){a=Math.abs(Math.trunc(a)); b=Math.abs(Math.trunc(b)); while(b){let t=a%b; a=b; b=t} return a}
function lcm(a,b){return a/gcd(a,b)*b}
function det(a,b){return a[0]*b[1]-a[1]*b[0]}
function cross(o,a,b){return (a[0]-o[0])*(b[1]-o[1])-(a[1]-o[1])*(b[0]-o[0])}
function hull(P){P=[...new Set(P.map(p=>p.join(',')))].map(s=>s.split(',').map(Number)).sort((a,b)=>a[0]-b[0]||a[1]-b[1]); if(P.length<=1)return P; let L=[],U=[]; for(const p of P){while(L.length>1&&cross(L.at(-2),L.at(-1),p)<=0)L.pop();L.push(p)} for(let i=P.length-1;i>=0;i--){let p=P[i];while(U.length>1&&cross(U.at(-2),U.at(-1),p)<=0)U.pop();U.push(p)} return L.slice(0,-1).concat(U.slice(0,-1))}
function bbox(P){return{minX:Math.min(...P.map(p=>p[0])),maxX:Math.max(...P.map(p=>p[0])),minY:Math.min(...P.map(p=>p[1])),maxY:Math.max(...P.map(p=>p[1]))}}
function norm(P){let v=hull(P); if(!v.length)return []; let b=bbox(v); return hull(v.map(p=>[p[0]-b.minX,p[1]-b.minY]))}
function cyc(P){let v=norm(P), n=v.length, best=null, bestv=null; for(const arr of [v,v.slice().reverse()]) for(let i=0;i<n;i++){let q=arr.slice(i).concat(arr.slice(0,i)), s=JSON.stringify(q); if(best===null||s<best){best=s;bestv=q}} return bestv||v}
function keyOf(P){return cyc(P).map(p=>p.join(',')).join(';')}
function area2(v){return Math.abs(v.reduce((s,p,i)=>s+det(p,v[(i+1)%v.length]),0))}
function signedArea2(v){return v.reduce((s,p,i)=>s+det(p,v[(i+1)%v.length]),0)}
function edges(v){return v.map((p,i)=>{let q=v[(i+1)%v.length]; return gcd(q[0]-p[0],q[1]-p[1])})}
function cycleSeq(a){let n=a.length,b=null; for(const arr of [a,a.slice().reverse()]) for(let i=0;i<n;i++){let s=arr.slice(i).concat(arr.slice(0,i)).join(','); if(b===null||s<b)b=s} return b}
function width(v,m){let vals=v.map(p=>m[0]*p[0]+m[1]*p[1]); return Math.max(...vals)-Math.min(...vals)}
function normals(v){return v.map((p,i)=>{let q=v[(i+1)%v.length],dx=q[0]-p[0],dy=q[1]-p[1],l=gcd(dx,dy);return[dy/l,-dx/l]})}
function mults(N){return N.map((n,i)=>Math.abs(det(N[(i-1+N.length)%N.length],n)))}
function dualDirs(v,S){let D=[]; for(let i=0;i<v.length;i++)for(let j=i+1;j<v.length;j++){let d=[v[i][0]-v[j][0],v[i][1]-v[j][1]]; if(d[0]||d[1])D.push(d)} let lines=[]; D.forEach(d=>{lines.push([d[0],d[1],S]); lines.push([d[0],d[1],-S])}); let xs=[],ys=[]; for(let i=0;i<lines.length;i++)for(let j=i+1;j<lines.length;j++){let [a,b,c]=lines[i], [d,e,f]=lines[j], Q=a*e-b*d; if(!Q)continue; let x=(c*e-b*f)/Q, y=(a*f-c*d)/Q; if(D.every(z=>Math.abs(z[0]*x+z[1]*y)<=S+1e-9)){xs.push(x);ys.push(y)}} let mnx,mxx,mny,mxy; if(xs.length){mnx=Math.floor(Math.min(...xs))-1;mxx=Math.ceil(Math.max(...xs))+1;mny=Math.floor(Math.min(...ys))-1;mxy=Math.ceil(Math.max(...ys))+1}else{let C=Math.max(...v.flat().map(Math.abs),S)+2;mnx=mny=-C;mxx=mxy=C} let R=[]; for(let a=mnx;a<=mxx;a++)for(let b=mny;b<=mxy;b++)if((a||b)&&gcd(a,b)==1&&width(v,[a,b])<=S)R.push([a,b]); return R}
function optDisplay(v){
  v=hull(v);
  let S0=Math.max(width(v,[1,0]),width(v,[0,1])), D=dualDirs(v,S0), W=new Map(D.map(m=>[m.join(','),width(v,m)]));
  let bestScore=null,bv=null,basis=null;
  function better(sc,best){if(!best)return true; for(let i=0;i<5;i++){if(sc[i]!==best[i])return sc[i]<best[i]} return sc[5]<best[5]}
  for(const m of D)for(const n of D){let de=m[0]*n[1]-m[1]*n[0]; if(Math.abs(de)!==1)continue; let w1=W.get(m.join(',')),w2=W.get(n.join(',')); let tv=v.map(p=>[m[0]*p[0]+m[1]*p[1],n[0]*p[0]+n[1]*p[1]]); let cv=cyc(tv), sc=[Math.max(w1,w2),w1,w2,w1*w2,w1+w2,JSON.stringify(cv)]; if(better(sc,bestScore)){bestScore=sc;bv=cv;basis=[m,n]}}
  return {v:bv||cyc(v),basis:basis||[[1,0],[0,1]],score:bestScore}
}
function optKey(v){return optDisplay(v).v.map(p=>p.join(',')).join(';')}
function onbd(p,v){return v.some((a,i)=>{let b=v[(i+1)%v.length];return cross(a,b,p)===0&&Math.min(a[0],b[0])<=p[0]&&p[0]<=Math.max(a[0],b[0])&&Math.min(a[1],b[1])<=p[1]&&p[1]<=Math.max(a[1],b[1])})}
function inside(p,v){let c=false; for(let i=0,j=v.length-1;i<v.length;j=i++){let a=v[i],b=v[j]; if(((a[1]>p[1])!==(b[1]>p[1]))&&p[0]<(b[0]-a[0])*(p[1]-a[1])/(b[1]-a[1])+a[0])c=!c} return c}
function latticePoints(v){let b=bbox(v), bd=[], inn=[]; for(let x=b.minX;x<=b.maxX;x++)for(let y=b.minY;y<=b.maxY;y++){let p=[x,y]; if(onbd(p,v))bd.push(p); else if(inside(p,v))inn.push(p)} return {bd,inn,all:bd.concat(inn)}}
function primitiveContent(v){let p0=v[0],g=0; for(const p of v.slice(1)){g=gcd(g,p[0]-p0[0]);g=gcd(g,p[1]-p0[1])} return g||1}
function centralFromPoints(P){let S=new Set(P.map(p=>p.join(','))), b=bbox(P), sx=b.minX+b.maxX, sy=b.minY+b.maxY; return P.every(p=>S.has((sx-p[0])+','+(sy-p[1])))}
function stats(v){v=hull(v); let e=edges(v), Vol=area2(v), B=e.reduce((a,b)=>a+b,0), I=(Vol-B+2)/2, N=B+I, Ns=normals(v), mm=mults(Ns), b=bbox(v), lw=Math.min(...Ns.map(n=>width(v,n))); return {v,V:v.length,e,edge:cycleSeq(e),Vol,B,I,N,area:Vol/2,Ns,mm,mult:cycleSeq(mm),smooth:mm.every(x=>x===1),content:primitiveContent(v),lw,box:[b.maxX-b.minX,b.maxY-b.minY],boxSq:Math.max(b.maxX-b.minX,b.maxY-b.minY),primEdges:e.filter(x=>x===1).length,maxEdge:Math.max(...e),minEdge:Math.min(...e)}}
function signatureFromStats(s){return `${s.Vol}|${s.V}|${s.B}|${s.I}|${s.edge}|${s.content}|${s.mult}`}
function codegree(s){return s.I>0?1:(s.B>3?2:3)}
function cmp(a,op,b){if(b===''||b===undefined||b===null)return true; b=+b; if(Number.isNaN(b))return true; return op==='≤'?a<=b:op==='≥'?a>=b:a===b}
function srcName(bit){return bit===3?'S+L':bit===2?'LDP':bit===1?'small':'unknown'}
function unpackDict(packed,arr){return typeof packed==='string'?packed.split('|'):(arr||[])}
function decodeMetaChunk(arr){if(MANIFEST&&(MANIFEST.metaEncoding==='uvarintB64v1'||MANIFEST.metaEncoding==='uvarintBinV2'))return decodeMetaVar(arr,MANIFEST.metaRowLength||20); if(typeof arr!=='string')return arr; arr=arr.trim(); if(!arr)return []; return arr.split(';').map(r=>r.split(',').map(x=>parseInt(x,36)))}
function unflatVertices(a){if(!a.length||Array.isArray(a[0]))return a; let v=[]; for(let i=0;i<a.length;i+=2)v.push([a[i],a[i+1]]); return v}
function decodeSource(code,srcFlag){if(Array.isArray(code)){if(srcFlag===1)return [`S:v${code[0]}:${code[1]}`]; if(srcFlag===2){let deg=String(code[4])+(code[5]&&code[5]!==1?`/${code[5]}`:''); return [`L:i${code[0]}:ID${code[1]}:order${code[2]}:degree${deg}`]}} if(typeof code==='string')return [code]; return []}
function parseB36(x){return x&&x[0]==='-'?-parseInt(x.slice(1),36):parseInt(x,36)}
function b64Bytes(txt){let bin=atob(txt.trim()), a=new Uint8Array(bin.length); for(let i=0;i<bin.length;i++)a[i]=bin.charCodeAt(i); return a}
function rawBytes(raw){if(raw instanceof Uint8Array)return raw; if(raw instanceof ArrayBuffer)return new Uint8Array(raw); return b64Bytes(raw)}
function readUVar(a,st){let x=0,s=0,b; do{b=a[st.i++]; if(b===undefined)throw new Error('Truncated varint data'); x+=(b&127)*2**s; s+=7; if(s>53)throw new Error('Varint exceeds JavaScript safe integer range')}while(b&128); return x}
function unzig(x){return (x>>>1)^-(x&1)}
function decodeMetaVar(raw,rowLen){let a=rawBytes(raw), st={i:0}, rows=readUVar(a,st), out=[]; for(let r=0;r<rows;r++){let row=[]; for(let j=0;j<rowLen;j++)row.push(readUVar(a,st)); out.push(row)} return out}
function decodeDataChunkVar(raw){let a=rawBytes(raw), st={i:0}, rows=readUVar(a,st), out=[]; for(let r=0;r<rows;r++){let nv=readUVar(a,st), flat=[]; for(let i=0;i<nv;i++)flat.push(unzig(readUVar(a,st))); let ns=readUVar(a,st), src=[]; for(let i=0;i<ns;i++)src.push(unzig(readUVar(a,st))); out.push([flat,src])} return out}
function decodePackedDataLine(line){let [vpart,spart='']=line.split('|'), flat=vpart?vpart.split('.').filter(Boolean).map(parseB36):[], src=spart?spart.split('.').filter(Boolean).map(parseB36):[]; return [flat,src]}
async function load(){MANIFEST=await fetch('data/manifest.json').then(r=>r.json()); $('#summary').innerHTML=`<div><strong>${MANIFEST.total.toLocaleString()}</strong> valid records</div><div><strong>${MANIFEST.rawRecords.toLocaleString()}</strong> raw records</div><div><strong>${MANIFEST.invalidFiltered.toLocaleString()}</strong> degenerate/invalid filtered</div><div><strong>${MANIFEST.metaChunks.length}</strong> metadata chunks</div>${MANIFEST.metaPacked?'<div><strong>packed</strong> metadata strings</div>':''}`; EDGE_DICT=unpackDict(MANIFEST.edgeDictPacked,MANIFEST.edgeDict); MULT_DICT=unpackDict(MANIFEST.multDictPacked,MANIFEST.multDict); let loaded=0; for(const ch of MANIFEST.metaChunks){let raw=await fetch('data/'+ch.file).then(r=>MANIFEST.metaEncoding==='uvarintBinV2'?r.arrayBuffer():((MANIFEST.metaEncoding==='base36csvtxt'||MANIFEST.metaEncoding==='uvarintB64v1')?r.text():r.json())); let arr=decodeMetaChunk(raw); for(const row of arr){if(MANIFEST.metaPacked){row[MIDX.edge]=EDGE_DICT[row[MIDX.edge]]; row[MIDX.mult]=MULT_DICT[row[MIDX.mult]]} META.push(row); BY_ID.set(row[MIDX.id],row); let sig=[row[MIDX.Vol],row[MIDX.V],row[MIDX.B],row[MIDX.I],row[MIDX.edge],row[MIDX.content],row[MIDX.mult]].join('|'); if(!BUCKET.has(sig))BUCKET.set(sig,[]); BUCKET.get(sig).push(row)} loaded+=arr.length; $('#load-status').textContent=`Loaded ${loaded.toLocaleString()} metadata rows…`; await new Promise(r=>setTimeout(r,0)) } $('#load-status').textContent=`Ready: ${META.length.toLocaleString()} searchable records.`; makeGrid(); renderMath(document.body); $('#search-status').textContent='Ready. Submit the empty form to display all records.'}
async function fetchRecord(row){let cno=row[MIDX.cno], off=row[MIDX.off], ch=MANIFEST.dataChunks[cno-1], f=ch.file; if(!DATA_CACHE.has(f)){if(MANIFEST.dataPacked==='flatSourceTxtV2'){let txt=await fetch('data/'+f).then(r=>r.text()); DATA_CACHE.set(f,txt.trim()?txt.trim().split('\n'):[])}else if(MANIFEST.dataPacked==='flatSourceVarB64V3'){let txt=await fetch('data/'+f).then(r=>r.text()); DATA_CACHE.set(f,decodeDataChunkVar(txt))}else if(MANIFEST.dataPacked==='flatSourceVarBinV4'){let buf=await fetch('data/'+f).then(r=>r.arrayBuffer()); DATA_CACHE.set(f,decodeDataChunkVar(buf))}else{DATA_CACHE.set(f, await fetch('data/'+f).then(r=>r.json()))}} let raw=DATA_CACHE.get(f)[off], rec=MANIFEST.dataPacked==='flatSourceTxtV2'?decodePackedDataLine(raw):raw; if(MANIFEST.dataPacked==='flatSourceV1'||MANIFEST.dataPacked==='flatSourceTxtV2'||MANIFEST.dataPacked==='flatSourceVarB64V3'||MANIFEST.dataPacked==='flatSourceVarBinV4')return {rid:row[MIDX.id],v:unflatVertices(rec[0]),src:decodeSource(rec[1],row[MIDX.src]),srcCount:1}; return {rid:rec[0],v:rec[1],src:rec[2]||[],srcCount:rec[3]||((rec[2]||[]).length)}}
function formValues(form){return Object.fromEntries(new FormData(form).entries())}
function filterRow(r,F){if(F.id){let q=parseInt(F.id.replace(/\D/g,'')); if(r[MIDX.id]!==q)return false} if(F.src&&String(r[MIDX.src])!==F.src)return false; if(!cmp(r[MIDX.Vol],F.volOp,F.vol))return false; if(!cmp(r[MIDX.V],F.vOp,F.V))return false; if(!cmp(r[MIDX.B],F.bOp,F.B))return false; if(!cmp(r[MIDX.I],F.iOp,F.I))return false; if(!cmp(r[MIDX.N],F.nOp,F.N))return false; if(!cmp(r[MIDX.lw],F.lwOp,F.lw))return false; if(!F._skipBox&&!cmp(r[MIDX.box],F.boxOp,F.box))return false; if(!cmp(r[MIDX.content],F.contentOp,F.content))return false; if(!cmp(r[MIDX.prim],F.primOp,F.prim))return false; if(!cmp(r[MIDX.maxE],F.maxEdgeOp,F.maxEdge))return false; if(!cmp(r[MIDX.minE],F.minEdgeOp,F.minEdge))return false; if(!cmp(r[MIDX.V]-2,F.rhoOp,F.rho))return false; if(!cmp(r[MIDX.I]>0?1:(r[MIDX.B]>3?2:3),F.codegOp,F.codeg))return false; if(F.edge&&r[MIDX.edge]!==F.edge.replace(/\s+/g,''))return false; if(F.mult&&r[MIDX.mult]!==F.mult.replace(/\s+/g,''))return false; if(F.smooth!==''&&String(r[MIDX.smooth])!==F.smooth)return false; if(F.centSym!==''&&String(r[MIDX.cent])!==F.centSym)return false; return true}
async function search(ev){ev&&ev.preventDefault(); renderStop=false; let F=formValues($('#search-form')), lim=F.limit===''?Infinity:Math.max(1,+F.limit||Infinity), needsExactBox=F.box!==''; if(needsExactBox)F._skipBox=true; let hits=[]; let t0=performance.now(), checked=0; for(const r of META){if(!filterRow(r,F))continue; if(needsExactBox){let rec=await fetchRecord(r), exactBox=stats(optDisplay(rec.v).v).boxSq; checked++; if(!cmp(exactBox,F.boxOp,F.box))continue; if(checked%250===0){$('#search-status').textContent=`Exact minimum-square checked ${checked.toLocaleString()} candidate rows…`; await new Promise(x=>setTimeout(x,0))}} hits.push(r); if(hits.length>=lim)break} $('#result-count').textContent=hits.length.toLocaleString(); $('#search-status').textContent=`Filtered ${META.length.toLocaleString()} rows${needsExactBox?` with ${checked.toLocaleString()} exact square checks`:''} in ${(performance.now()-t0).toFixed(0)} ms. Rendering…`; $('#results').innerHTML=''; await renderResults(hits,$('#results')); $('#search-status').textContent=`${hits.length.toLocaleString()} result${hits.length===1?'':'s'} rendered.`}
async function renderResults(rows,container){container.innerHTML=''; let batch=300; for(let i=0;i<rows.length&&!renderStop;i+=batch){let frag=document.createDocumentFragment(); for(const r of rows.slice(i,i+batch))frag.appendChild(resultElement(r)); container.appendChild(frag); await new Promise(r=>setTimeout(r,0))} if(!rows.length)container.innerHTML='<p class="empty">No matching records.</p>'}
function resultElement(r){let el=document.createElement('div'); el.className='result'; el.innerHTML=`<div class="result-main"><div><div class="result-title">${id(r[MIDX.id])} <span class="chip">${srcName(r[MIDX.src])}</span></div><div class="chips"><span class="chip">Vol ${r[MIDX.Vol]}</span><span class="chip">V ${r[MIDX.V]}</span><span class="chip">B ${r[MIDX.B]}</span><span class="chip">I ${r[MIDX.I]}</span><span class="chip">N ${r[MIDX.N]}</span><span class="chip">lw ${r[MIDX.lw]}</span><span class="chip">edge [${r[MIDX.edge]}]</span></div></div><div class="result-actions"><button type="button" data-act="open">Open</button><button type="button" data-act="download">Download</button></div></div><div class="detail-slot" hidden></div>`; let slot=el.querySelector('.detail-slot'); el.querySelector('[data-act="open"]').onclick=async()=>{if(!slot.hidden){slot.hidden=true;slot.innerHTML='';return} slot.hidden=false; slot.innerHTML='<p class="empty">Loading record…</p>'; await openRecord(r,slot)}; el.querySelector('[data-act="download"]').onclick=()=>downloadRecordData(r); return el}
function transformDisplay(v){let base=optDisplay(v).v; let b=bbox(base), W=b.maxX-b.minX, H=b.maxY-b.minY; let P=base.map(p=>[p[0]-b.minX,p[1]-b.minY]); for(let k=0;k<((viewState.rot%4)+4)%4;k++){P=P.map(p=>[p[1],W-p[0]]); [W,H]=[H,W]} if(viewState.fx)P=P.map(p=>[W-p[0],p[1]]); if(viewState.fy)P=P.map(p=>[p[0],H-p[1]]); return cyc(P)}
async function openRecord(row,slot,originHint=null){try{let rec=await fetchRecord(row); currentOpen={row,rec,slot}; selectedOrigin=originHint; viewState={rot:0,fx:false,fy:false}; renderRecord()}catch(e){console.error('openRecord failed',e); if(slot)slot.innerHTML=`<div class="card error-card"><h3>Could not render record</h3><p class="empty">${e&&e.message?e.message:e}</p><pre class="code-box">${String(e&&e.stack?e.stack:e).replace(/[<>&]/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]))}</pre></div>`}}
function renderRecord(){let {row,rec,slot}=currentOpen; let v=transformDisplay(rec.v), s=stats(v), P=latticePoints(v); if((!selectedOrigin||!P.inn.some(p=>p[0]===selectedOrigin[0]&&p[1]===selectedOrigin[1]))&&P.inn.length===1)selectedOrigin=P.inn[0]; let verts=new Set(v.map(p=>p.join(','))), boundaryNonVerts=P.bd.filter(p=>!verts.has(p.join(','))); let G=[{P:boundaryNonVerts,c:'boundary',r:3,label:'boundary lattice point'},{P:P.inn,c:'interior',r:4,label:'interior lattice point'},{P:v,c:'vertex',r:5,label:'vertex'}]; if(selectedOrigin)G.push({P:[selectedOrigin],c:'origin',r:7,label:'selected origin'}); let cent=centroidData(v,P); let CG=[{P:[cent.area.point],c:'centA',r:6,label:'area centroid'},{P:[cent.all.point],c:'centL',r:6,label:'lattice centroid'},{P:[cent.boundary.point],c:'centB',r:6,label:'boundary centroid'}]; if(cent.interior)CG.push({P:[cent.interior.point],c:'centI',r:6,label:'interior centroid'}); slot.innerHTML=`<div class="record-grid"><div class="wide-figures"><div class="card"><h3>${id(row[MIDX.id])}: minimum-square display</h3><div class="toggle-row"><button id="rotL">↺ 90°</button><button id="rotR">↻ 90°</button><button id="flipX">left/right flip</button><button id="flipY">up/down flip</button>${copyButton(v)}</div><div class="figure-box" id="poly-figure">${svgPolygon(v,G,{large:true})}</div><p class="subtle">Vertices are red, boundary lattice points blue, interior lattice points green, and the selected origin is black. If the polygon has a unique interior lattice point, it is selected automatically.</p><div class="point-buttons">${P.inn.map(p=>`<button data-p="${p.join(',')}" class="${selectedOrigin&&selectedOrigin[0]===p[0]&&selectedOrigin[1]===p[1]?'active':''}">(${p[0]},${p[1]})</button>`).join('')||'<span class="subtle">No interior lattice points.</span>'}</div></div><div class="card"><h3>Centroids</h3><div class="toggle-row">${copyButton(v)}</div><div class="figure-box">${svgPolygon(v,CG,{large:false})}</div><div class="coords">${centroidText(cent)}</div></div></div><div>${basicSection(s,row,rec,P)}${symmetrySection(s,P)}${ehrhartSection(s)}${toricSection(s,v,P)}${algebraicSection(s)}${minkowskiSection(s,P)}${tropicalSection(s)}${discriminantSection(s)}</div><div>${fanSection(s,v)}${pointedSection(s,v)}${neighborSection()}</div></div>`; slot.querySelector('#rotL').onclick=()=>{viewState.rot--;selectedOrigin=null;renderRecord()}; slot.querySelector('#rotR').onclick=()=>{viewState.rot++;selectedOrigin=null;renderRecord()}; slot.querySelector('#flipX').onclick=()=>{viewState.fx=!viewState.fx;selectedOrigin=null;renderRecord()}; slot.querySelector('#flipY').onclick=()=>{viewState.fy=!viewState.fy;selectedOrigin=null;renderRecord()}; slot.querySelectorAll('#poly-figure .interior,.point-buttons button[data-p]').forEach(el=>el.onclick=()=>{selectedOrigin=el.dataset.p.split(',').map(Number);renderRecord()}); let nb=slot.querySelector('#compute-neighbors'); if(nb)nb.onclick=()=>computeNeighbors(v,slot); attachBlowupControls(v,slot); let bu=slot.querySelector('#compute-blowup'); if(bu)bu.onclick=()=>computeBlowup(v,slot); let per=slot.querySelector('#compute-period'); if(per)per.onclick=()=>computeMirrorPeriod(v,slot); let demo=slot.querySelector('#period-demo'); if(demo)demo.onclick=()=>computePeriodDemo(slot); let cc=slot.querySelector('#compute-curves'); if(cc)cc.onclick=()=>computeCurveCounting(s,slot); attachCopyButtons(slot); renderMath(slot)}
function svgPolygon(v,groups=[],opts={}){let all=v.concat(groups.flatMap(g=>g.P)); let b=bbox(all), pad=opts.large?36:28, maxW=opts.large?760:520, maxH=opts.large?520:360; let sx=maxW/Math.max(1,b.maxX-b.minX+1), sy=maxH/Math.max(1,b.maxY-b.minY+1), sc=Math.min(sx,sy,48); let W=(b.maxX-b.minX)*sc+2*pad, H=(b.maxY-b.minY)*sc+2*pad; let X=p=>pad+(p[0]-b.minX)*sc, Y=p=>H-pad-(p[1]-b.minY)*sc; let s=`<svg width="100%" height="${H}" viewBox="0 0 ${W} ${H}" role="img">`; for(let x=Math.floor(b.minX);x<=Math.ceil(b.maxX);x++)s+=`<line class="${x===0?'axisline':'gridline'}" x1="${X([x,b.minY])}" y1="${Y([x,b.minY])}" x2="${X([x,b.maxY])}" y2="${Y([x,b.maxY])}"/>`; for(let y=Math.floor(b.minY);y<=Math.ceil(b.maxY);y++)s+=`<line class="${y===0?'axisline':'gridline'}" x1="${X([b.minX,y])}" y1="${Y([b.minX,y])}" x2="${X([b.maxX,y])}" y2="${Y([b.maxX,y])}"/>`; s+=`<polygon class="poly" points="${v.map(p=>X(p)+','+Y(p)).join(' ')}"/>`; for(const g of groups)for(const p of g.P){s+=`<circle class="${g.c}" cx="${X(p)}" cy="${Y(p)}" r="${g.r||4}" data-p="${p[0]},${p[1]}"><title>${g.label||g.c}: (${fmtPoint(p)})</title></circle>`} return s+'</svg>'}
function fmtPoint(p){return `${numFmt(p[0])}, ${numFmt(p[1])}`}
function numFmt(x){return Number.isInteger(x)?String(x):String(Math.round(x*10000)/10000)}
function frac(n,d=1){if(d<0){n=-n;d=-d} if(n===0)return '0'; let g=gcd(n,d); n/=g; d/=g; return d===1?String(n):`${n}/${d}`}
