function fracText(a){return frac(a.n,a.d)}
function fracLatex(a){return a.d===1?String(a.n):`\\frac{${a.n}}{${a.d}}`}
function fracFromNumber(x){if(Number.isInteger(x))return String(x); let d=1000000,n=Math.round(x*d),g=gcd(n,d); return `${n/g}/${d/g}`}
function avgFrac(points){let sx=0,sy=0; for(const p of points){sx+=p[0];sy+=p[1]} return {point:[sx/points.length,sy/points.length],text:`(${frac(sx,points.length)}, ${frac(sy,points.length)})`}}
function centroidData(v,P){let A=signedArea2(v), sx=0,sy=0; for(let i=0;i<v.length;i++){let p=v[i],q=v[(i+1)%v.length],d=det(p,q); sx+=(p[0]+q[0])*d; sy+=(p[1]+q[1])*d} let area={point:[sx/(3*A),sy/(3*A)],text:`(${frac(sx,3*A)}, ${frac(sy,3*A)})`}; let all=avgFrac(P.all), boundary=avgFrac(P.bd), interior=P.inn.length?avgFrac(P.inn):null; return {area,all,boundary,interior}}
function centroidText(c){return `Area centroid: ${c.area.text}<br>Lattice-point centroid: ${c.all.text}<br>Boundary lattice centroid: ${c.boundary.text}<br>${c.interior?`Interior lattice centroid: ${c.interior.text}`:'Interior lattice centroid: undefined'}`}
function kvTable(rows){return `<div class="kv-table">${rows.map(r=>`<div class="kv-name">${r[0]}</div><div class="kv-value">${r[1]}</div>`).join('')}</div>`}
function detail(title,body){return `<details class="formula"><summary>${title}</summary><div class="body">${body}</div></details>`}
function mathInline(x){return `\\(${x}\\)`}
function hodgeDiamond(rho){let rows=[['1'],['0','0'],['0',String(rho),'0'],['0','0'],['1']]; return `<div class="hodge-diamond" aria-label="Hodge diamond">${rows.map(r=>`<div class="hodge-row" style="--cols:${r.length}">${r.map(c=>`<span>${c}</span>`).join('')}</div>`).join('')}</div>`}
function sectionIntro(txt){return `<p class="section-note">${txt}</p>`}
function primitiveDir(p,q){let dx=q[0]-p[0],dy=q[1]-p[1],g=gcd(dx,dy); dx/=g; dy/=g; if(dx<0||(dx===0&&dy<0)){dx=-dx;dy=-dy} return [dx,dy]}
