function countParallelPairs(v){let dirs=edgeDirections(v).map(d=>d.join(',')), m=new Map(); dirs.forEach(d=>m.set(d,(m.get(d)||0)+1)); return [...m.entries()].filter(e=>e[1]>1).map(e=>`${e[1]}×(${e[0]})`).join('; ')||'none'}
function interiorPolygon(v){let P=latticePoints(v).inn; return P.length? hull(P):[]}
function basicSection(s,row,rec,P){let aut=automorphisms(s.v); let group=autGroupName(aut); let od=optDisplay(s.v), square=od.score?`${od.score[0]}×${od.score[0]} (chosen rectangle ${od.score[1]}×${od.score[2]})`:s.boxSq; return `<div class="card"><h3>Basic geometry</h3>${sectionIntro('Combinatorial invariants of the lattice polygon, stable under affine unimodular transformations.')}${kvTable([
['Sources',`${srcName(row[MIDX.src])}; stored labels: ${(rec.src||[]).slice(0,6).join('<br>')}${rec.srcCount>6?'<br>…':''}`],['Total lattice points',s.N],['Number of vertices',s.V],['Boundary lattice points',s.B],['Interior lattice points',s.I],['Normalized area',s.Vol],['Euclidean area',frac(s.Vol,2)],['Lattice dilation factor',s.content],['Edge length cycle',`[${s.edge}]`],['Minimum displayed n×n square',square],['Lattice width',s.lw],['Automorphism group',`${group}; order ${aut.order}`],['Centrally symmetric',centralFromPoints(P.all)?'yes':'no'],['Smooth / Delzant polygon',s.smooth?'yes':'no']])}${detail('Definitions and formulas',`The lattice edge length of an edge vector ${mathInline('u_i=(a_i,b_i)')} is ${mathInline('\\ell_i=\\gcd(|a_i|,|b_i|)')}. Hence ${mathInline('B=\\sum_i\\ell_i')}. The normalized area is ${mathInline('\\operatorname{Vol}(P)=2\\operatorname{Area}(P)')}, and Pick’s theorem gives ${mathInline('I=\\operatorname{Area}(P)-B/2+1')}. The displayed square size is the minimum of ${mathInline('\\max(\\operatorname{width}_{m_1}(P),\\operatorname{width}_{m_2}(P))')} over unimodular bases ${mathInline('(m_1,m_2)')} of the dual lattice. If several bases give the same square size, this build chooses the one with the smaller horizontal width first, i.e. the narrower minimum rectangle.`)}</div>`}
function ehrhartSection(s){let h1=s.N-3,h2=s.I,cg=codegree(s); let rows=[]; for(let k=0;k<=10;k++){let L=(s.Vol*k*k+s.B*k+2)/2; let Li=k>0?(s.Vol*k*k-s.B*k+2)/2:''; rows.push(`<tr><td>${k}</td><td>${L}</td><td>${Li}</td></tr>`)} return `<div class="card"><h3>Ehrhart, Hilbert and adjunction data</h3>${sectionIntro('The polygon is the moment polytope of a polarized projective toric surface, so lattice-point counts are dimensions of sections.')}${kvTable([
['Ehrhart polynomial',mathInline(`L_P(k)=(${s.Vol}k^2+${s.B}k+2)/2`)],['Interior Ehrhart polynomial',mathInline(`L_{P^\\circ}(k)=(${s.Vol}k^2-${s.B}k+2)/2`)],['Ehrhart / Hilbert series',mathInline(`\\dfrac{1+${h1}t+${h2}t^2}{(1-t)^3}`)],['\\(h^*\\)-vector',mathInline(`(1,${h1},${h2})`)],['Codegree',cg],['\\(h^*\\)-degree',3-cg]])}<details class="formula"><summary>Table of \(\#(kP\\cap M)\) and \(\#((kP)^\\circ\\cap M)\)</summary><table class="small-table"><thead><tr><th>k</th><th>\(\#(kP\cap M)\)</th><th>\(\#((kP)^\circ\cap M)\)</th></tr></thead><tbody>${rows.join('')}</tbody></table></details>${detail('Mathematical background',`For the polarized toric surface ${mathInline('(X_P,L_P)')}, ${mathInline('h^0(X_P,kL_P)=\\#(kP\\cap M)')}. In dimension two Ehrhart’s formula is ${mathInline('L_P(k)=\\operatorname{Area}(P)k^2+(B/2)k+1')}; Ehrhart reciprocity gives the interior count. The numerator ${mathInline('1+h_1^*t+h_2^*t^2')} records the Hilbert series of the semigroup algebra.`)}</div>`}
function localGorensteinIndex(a,b){let D=det(a,b); let xNum=b[1]-a[1], yNum=a[0]-b[0]; let dx=Math.abs(D)/gcd(xNum,D), dy=Math.abs(D)/gcd(yNum,D); return lcm(dx,dy)}
function torsionOrder(rays){let g=0; for(let i=0;i<rays.length;i++)for(let j=i+1;j<rays.length;j++)g=gcd(g,det(rays[i],rays[j])); return Math.abs(g)||1}
function selfIntersectionFractions(Ns){let n=Ns.length, out=[]; for(let i=0;i<n;i++){let num=-det(Ns[(i-1+n)%n],Ns[(i+1)%n]), den=det(Ns[(i-1+n)%n],Ns[i])*det(Ns[i],Ns[(i+1)%n]); out.push(fracObj(num,den))} return out}
function selfIntersections(Ns){return selfIntersectionFractions(Ns).map(fracText)}
function anticanonicalSquare(Ns){let n=Ns.length, total={n:0,d:1}; for(const f of selfIntersectionFractions(Ns))total=fracAdd(total,f); for(let i=0;i<n;i++){let den=Math.abs(det(Ns[i],Ns[(i+1)%n])); total=fracAdd(total,fracObj(2,den))} return total}
function coneHNF(a,b){let r=Math.abs(det(a,b)); if(r===1)return 'smooth'; let m=bezoutVector(a); let beta=det(a,b); if(beta<0)m=[-m[0],-m[1]]; let alpha=det(b,m); alpha=((alpha%r)+r)%r; return `cone ((1,0),(${alpha},${r}))`}
function bezoutVector(u){function eg(a,b){if(b===0)return [Math.sign(a)||1,0,Math.abs(a)]; let [x,y,g]=eg(b,a%b); return [y,x-Math.trunc(a/b)*y,g]} let [A,B]=eg(u[0],u[1]); return [-B,A]}

function fracNeg(a){return {n:-a.n,d:a.d}}
function fracSub(a,b){return fracAdd(a,fracNeg(b))}
function fracMul(a,b){return fracObj(a.n*b.n,a.d*b.d)}
function fracDiv(a,b){return fracObj(a.n*b.d,a.d*b.n)}
function fracHtml(a){return mathInline(fracLatex(a))}
function solveInBasis(a,b,c){let D=det(a,b); return [fracObj(det(c,b),D),fracObj(det(a,c),D)]}
function fracVecText(v){return `[${v.map(fracText).join(', ')}]`}
function fracVecLatex(v){return mathInline(`(${v.map(fracLatex).join(',')})`)}
function divisorClassData(Ns){let n=Ns.length,best=null; for(let i=0;i<n;i++)for(let j=i+1;j<n;j++){let D=Math.abs(det(Ns[i],Ns[j])); if(D&&(!best||D<best.D))best={a:i,b:j,D}} if(!best)return {pivot:[],free:[],coords:[]}; let free=[]; for(let i=0;i<n;i++)if(i!==best.a&&i!==best.b)free.push(i); let coords=Ns.map(_=>free.map(()=>fracObj(0,1))); free.forEach((idx,k)=>coords[idx][k]=fracObj(1,1)); for(const piv of [best.a,best.b]){let vec=[]; for(const idx of free){let c=[-Ns[idx][0],-Ns[idx][1]], sol=solveInBasis(Ns[best.a],Ns[best.b],c); vec.push(sol[piv===best.a?0:1])} coords[piv]=vec} return {pivot:[best.a,best.b],free,coords,det:best.D}}
function intersectionMatrix(Ns){let n=Ns.length,self=selfIntersectionFractions(Ns), M=[]; for(let i=0;i<n;i++){M[i]=[]; for(let j=0;j<n;j++)M[i][j]=fracObj(0,1); M[i][i]=self[i]} for(let i=0;i<n;i++){let j=(i+1)%n, den=Math.abs(det(Ns[i],Ns[j])); M[i][j]=M[j][i]=fracObj(1,den)} return M}
function matrixHtml(M,heads){return `<div class="matrix-scroll"><table class="small-table matrix-table"><thead><tr><th></th>${heads.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${M.map((r,i)=>`<tr><th>${heads[i]}</th>${r.map(x=>`<td>${fracHtml(x)}</td>`).join('')}</tr>`).join('')}</tbody></table></div>`}
function divisorVectorTable(s){let cls=divisorClassData(s.Ns), self=selfIntersectionFractions(s.Ns), heads=cls.free.map(i=>`[D_${i+1}]`); return `<table class="small-table divisor-table"><thead><tr><th>divisor</th><th>ray</th><th>${mathInline('D_i^2')}</th><th>${mathInline('L\\cdot D_i')}</th><th>class vector in rational basis ${heads.length?heads.join(', '):'—'}</th></tr></thead><tbody>${s.Ns.map((n,i)=>`<tr><td>${mathInline('D_'+(i+1))}</td><td>(${n[0]},${n[1]})</td><td>${fracHtml(self[i])}</td><td>${s.e[i]}</td><td>${cls.coords[i]?fracVecLatex(cls.coords[i]):'—'}</td></tr>`).join('')}</tbody></table>`}
function toricSection(s,v,P){let coneOrders=s.mm.join(', '), Kidx=s.Ns.map((n,i)=>localGorensteinIndex(s.Ns[(i-1+s.V)%s.V],n)).reduce((a,b)=>lcm(a,b),1), tors=torsionOrder(s.Ns), cl=tors===1?mathInline(`\\mathbb Z^{${s.V-2}}`): mathInline(`\\mathbb Z^{${s.V-2}}\\oplus\\mathbb Z/${tors}\\mathbb Z`), hnf=s.Ns.map((n,i)=>coneHNF(s.Ns[(i-1+s.V)%s.V],n)), k2=anticanonicalSquare(s.Ns), divCls=divisorClassData(s.Ns), heads=s.Ns.map((_,i)=>mathInline('D_'+(i+1))); return `<div class="card"><h3>Toric surface, divisors and class group</h3>${sectionIntro('Data of the normal fan, invariant divisors, rational intersection pairing and birational toric modifications.')}${kvTable([
['Normal fan rays',s.Ns.map(n=>`(${n[0]},${n[1]})`).join(', ')],['Cone multiplicities',coneOrders],['Local cone normal forms',hnf.join('; ')],['Smooth surface',s.smooth?'yes':'no'],['\\(K_X\\) Cartier index',Kidx],['Class group',cl],['Rational class basis',divCls.free.length?divCls.free.map(i=>mathInline(`[D_${i+1}]`)).join(', '):'rank 0'],['Picard rank / \\(\\rho\\)',s.V-2],['Cox variables',s.V],['\\(L^2\\)',s.Vol],['\\((-K_X)\\cdot L\\)',s.B],['\\((-K_X)^2\\)',mathInline(fracLatex(k2))],['\\(L\\cdot D_i\\)',s.e.join(', ')],['Invariant divisor self-intersections',selfIntersectionFractions(s.Ns).map(f=>mathInline(fracLatex(f))).join(', ')]])}<details class="formula"><summary>Invariant divisors in a rational class-group basis</summary>${divisorVectorTable(s)}<p class="subtle">The displayed basis is a rational splitting of ${mathInline('\\operatorname{Cl}(X)_\\mathbb Q')}; torsion, when present, is still recorded in the class-group row.</p></details><details class="formula"><summary>Complete invariant-divisor intersection matrix</summary>${matrixHtml(intersectionMatrix(s.Ns),heads)}</details>${blowupSection(s,v,P)}${detail('Divisor dictionary and intersection formulas',`The primitive outward normals ${mathInline('\\nu_i')} are the rays of the normal fan. For adjacent rays, the affine cone multiplicity is ${mathInline('|\\det(\\nu_i,\\nu_{i+1})|')}. The torus-invariant Weil divisor group is free on the ray divisors, and the class group is the cokernel of ${mathInline('M\\to\\mathbb Z^r')}, ${mathInline('m\\mapsto(\\langle m,\\nu_i\\rangle)_i')}. For a simplicial toric surface, ${mathInline('D_i^2=-\\det(\\nu_{i-1},\\nu_{i+1})/(\\det(\\nu_{i-1},\\nu_i)\\det(\\nu_i,\\nu_{i+1}))')} and ${mathInline('D_i\\cdot D_{i+1}=1/|\\det(\\nu_i,\\nu_{i+1})|')}. Since ${mathInline('-K_X=\\sum_i D_i')}, ${mathInline('(-K_X)^2')} is computed from this rational matrix.`)}</div>`}
function adjointTower(v){let out=[], cur=hull(v), level=0; while(cur.length>=3&&area2(cur)>0&&level<12){let P=latticePoints(cur), inn=P.inn, st=stats(cur); out.push({level,vertices:cur,Vol:st.Vol,B:st.B,I:st.I,N:st.N}); if(!inn.length)break; cur=hull(inn); level++} return out}
function svgAdjointTower(v){let tower=adjointTower(v), polys=tower.map(t=>t.vertices), all=polys.flat(), b=bbox(all), pad=30,maxW=520,maxH=360,sc=Math.min(maxW/Math.max(1,b.maxX-b.minX+1),maxH/Math.max(1,b.maxY-b.minY+1),44), W=(b.maxX-b.minX)*sc+2*pad,H=(b.maxY-b.minY)*sc+2*pad, X=p=>pad+(p[0]-b.minX)*sc,Y=p=>H-pad-(p[1]-b.minY)*sc; return `<svg width="100%" height="${H}" viewBox="0 0 ${W} ${H}" class="adjoint-svg"><text class="label" x="8" y="18">Adjoint polygon tower</text>${polys.map((poly,i)=>`<polygon class="adjoint-poly adjoint-${i%4}" points="${poly.map(p=>X(p)+','+Y(p)).join(' ')}"><title>P^(${i})</title></polygon>`).join('')}${tower.map((t,i)=>`<text class="label" x="${W-110}" y="${24+16*i}">P^(${i}): I=${t.I}, B=${t.B}</text>`).join('')}</svg>`}
function minWidthDirection(v){let s=stats(v), dirs=dualDirs(v,s.lw).filter(m=>width(v,m)===s.lw); return dirs[0]||[1,0]}
