function updateSelectedHull(){let P=selectedGridPoints(), out=$('#selected-summary'), layer=$('#draw-hull-layer'); DRAW_AUTO_ORIGIN=null; $$('#point-grid .grid-point').forEach(c=>c.classList.toggle('selected',DRAW_SELECTED.has(c.dataset.p))); if(!layer)return; if(P.length<3){out.textContent=`${P.length} point(s) selected.`; layer.innerHTML=''; return} let h=hull(P), A=area2(h); out.textContent=`${P.length} point(s) selected; current hull has ${h.length} vertices and normalized volume ${A}.`; if(A===0){layer.innerHTML=''; out.textContent+=' Selected points are collinear.'; return} let selectedInterior=P.filter(p=>!onbd(p,h)&&inside(p,h)); let allInterior=latticePoints(h).inn; if(selectedInterior.length===1)DRAW_AUTO_ORIGIN=selectedInterior[0]; else if(allInterior.length===1)DRAW_AUTO_ORIGIN=allInterior[0]; if(DRAW_AUTO_ORIGIN)out.textContent+=` Auto-selected interior point: (${DRAW_AUTO_ORIGIN[0]},${DRAW_AUTO_ORIGIN[1]}).`; let svg=$('.draw-grid-svg'), vb=svg.viewBox.baseVal, n=DRAW_GRID_N, pad=34, origin=Math.floor(n/2), step=(vb.width-2*pad)/(n-1), X=x=>pad+(x+origin)*step, Y=y=>vb.height-pad-(y+origin)*step; layer.innerHTML=`<polygon class="draw-hull" points="${h.map(p=>X(p[0])+','+Y(p[1])).join(' ')}"/>${h.map(p=>`<circle class="draw-hull-vertex" cx="${X(p[0])}" cy="${Y(p[1])}" r="7"><title>hull vertex (${p[0]},${p[1]})</title></circle>`).join('')}${DRAW_AUTO_ORIGIN?`<circle class="draw-auto-origin" cx="${X(DRAW_AUTO_ORIGIN[0])}" cy="${Y(DRAW_AUTO_ORIGIN[1])}" r="8"><title>auto-selected interior point (${DRAW_AUTO_ORIGIN[0]},${DRAW_AUTO_ORIGIN[1]})</title></circle>`:''}`}
function svgTransformComparison(inputHull,targetHull,T,marked=null){let moved=T?inputHull.map(p=>applyAffine(p,T)):inputHull, all=moved.concat(targetHull).concat(marked?[marked]:[]), b=bbox(all), pad=24, maxW=360, maxH=230, sx=maxW/Math.max(1,b.maxX-b.minX+1), sy=maxH/Math.max(1,b.maxY-b.minY+1), sc=Math.min(sx,sy,42), W=(b.maxX-b.minX)*sc+2*pad, H=(b.maxY-b.minY)*sc+2*pad, X=p=>pad+(p[0]-b.minX)*sc, Y=p=>H-pad-(p[1]-b.minY)*sc; return `<svg class="shape-map-svg" width="100%" height="${H}" viewBox="0 0 ${W} ${H}"><polygon class="poly" points="${targetHull.map(p=>X(p)+','+Y(p)).join(' ')}"/><polygon class="mapped-poly" points="${moved.map(p=>X(p)+','+Y(p)).join(' ')}"/>${targetHull.map(p=>`<circle class="vertex" cx="${X(p)}" cy="${Y(p)}" r="4"/>`).join('')}${moved.map(p=>`<circle class="mapped-point" cx="${X(p)}" cy="${Y(p)}" r="2.8"/>`).join('')}${marked?`<circle class="origin" cx="${X(marked)}" cy="${Y(marked)}" r="6"><title>mapped selected interior (${marked[0]},${marked[1]})</title></circle>`:''}</svg>`}
async function renderShapeResults(rows,container,inputHull){container.innerHTML=''; for(const r of rows){let rec=await fetchRecord(r), dv=optDisplay(rec.v).v, T=aglTransform(inputHull,dv), el=resultElement(r), main=el.querySelector('.result-main'); let info=document.createElement('div'); info.className='shape-transform-info'; let mappedOrigin=DRAW_AUTO_ORIGIN&&T?applyAffine(DRAW_AUTO_ORIGIN,T):null; info.innerHTML=`<div><strong>Affine transform from drawn hull to minimum-square display:</strong> ${transformLatex(T)}<br><span class="subtle">${transformPlain(T)}${mappedOrigin?`; selected interior maps to (${mappedOrigin[0]},${mappedOrigin[1]})`:''}</span></div><div><div class="figure-tools">${copyButton(dv)}</div>${svgTransformComparison(inputHull,dv,T,mappedOrigin)}</div>`; main.insertAdjacentElement('afterend',info); container.appendChild(el); attachCopyButtons(info); await new Promise(resolve=>setTimeout(resolve,0))} renderMath(container)}
async function shapeSearch(){let P=selectedGridPoints(), h=hull(P), out=$('#shape-result'); if(P.length<3||h.length<3||area2(h)===0){out.innerHTML='<p class="empty">Select at least three non-collinear lattice points.</p>'; return} out.innerHTML='<p class="empty">Searching invariant bucket with exact AGL₂(ℤ) verification…</p>'; let hits=await findEquivalent(h,50); if(!hits.length){out.innerHTML='<p class="empty">No strict match found in the database.</p>';return} out.innerHTML=`<p class="small-note">${hits.length} match(es). ${DRAW_AUTO_ORIGIN?`Auto-selected interior point in the drawn polygon: (${DRAW_AUTO_ORIGIN[0]},${DRAW_AUTO_ORIGIN[1]}).`:''} Each card shows an affine unimodular map from your drawn hull to the stored polygon.</p><div class="results"></div>`; await renderShapeResults(hits,out.querySelector('.results'),h)}

$('#search-form').onsubmit=search; $('#stop-render').onclick=()=>{renderStop=true}; $('#make-grid').onclick=makeGrid; $('#clear-grid').onclick=()=>{DRAW_SELECTED.clear(); DRAW_AUTO_ORIGIN=null; updateSelectedHull(); $('#shape-result').innerHTML=''}; $('#shape-search').onclick=shapeSearch; window.addEventListener('load',load);
